// 2.8.3 HF306 | 2023-10-13 |raj |  DFCT0012229 - Address GlideRecordSecure Issues in the Event swap Performance Fix
// 2.8.3HF | 2023-09-24 | DFCT0012180 - DIA - Tasks not getting created when using "Select to Create Subtasks for Each Member in OU" with 30 OU Members or more under the primary assignee
// Script Continued Below

// DFCT0012229 - this is called only from an event where the admin many not have the needed permissions.
//               getting a new reference to the record as glide record, not glide record secure 
//               this is to ensure processing of this record can be performaed without acls
taskerUpdateSubtaskReviewers(current);
// RAJ NOTE: just call the UI Action script include already in 2.6 here instead of having the code in the event.
function taskerUpdateSubtaskReviewers(task){
	tcs = new TaskerCommonScriptingMethods();
	try{
		if(task.tasker_type.work_type != "review_item") { //Standard Task Type
			var taskTableName = "x_153465_discovert_route_task_instance";
			tcs.queryRelated(taskTableName, [{"parent":task.sys_id}], function(sub_task) {
				//check if the child has a reviewer lock
				// DFCT0010871
				if(!sub_task.reviewer_manual_update && sub_task.tasker_type.work_type != "review_item") {
					//if not, then set child reviewer to parent assigned
					if(task.assigned_to) {

						sub_task.u_reviewer = task.assigned_to;
						sub_task.update();
					} else{
						sub_task.u_reviewer = task.u_task_requester;
						sub_task.update();
					}
				}
			});
		}
	}catch(e) {
		gs.error("Tasker - in DiscoverTasker_UpdateSubtaskReviewer Exception: " + e.message);
	}
}
